import { revalidatePath, revalidateTag } from 'next/cache'; import { createClient } from '@/lib/supabase/server';
async function requireAdminUid(supabase): claims=getClaims(); if(!claims) return null; return claims.sub;
export async function approveCircle(circleId): {ok,error?} {
  supabase=await createClient(); uid=...; if(!uid) return {ok:false,error:'unauthenticated'};
  update circles set status='approved', reviewed_by=uid, reviewed_at=new Date().toISOString() where id=circleId; // RLS is_admin() 가 비관리자 차단
  if(error) return {ok:false,error}; revalidatePath('/admin/circles'); revalidateTag('circles',{expire:0}); // TODO(T-020): 오너 이메일(승인) 알림
  return {ok:true}; }
export async function rejectCircle(circleId, reason): {ok,error?} {
  const r=reason?.trim(); if(!r) return {ok:false,error:'却下理由は必須です'};
  if(r.length>500) return {ok:false,error:'却下理由は500文字以内'};
  update circles set status='rejected', rejection_reason=r, reviewed_by=uid, reviewed_at=now where id=circleId; revalidatePath('/admin/circles'); // TODO(T-020): 거절 알림
  return {ok:true}; }
